import React from 'react'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'
import avatar from '../components/static/HedMayner.png'


const MePageWrapper = styled.div `
width:90%;
margin:0 auto;
`

const MeHeader = styled.div `
display:flex;
justify-content:space-between;
align-items:center;
margin:20px 0;
`

const MeBody = styled.div `
display:flex;
justify-content:center;
align-items:center;
`

const Avatar = styled.div `
border-radius:50%;
width:150px;
height:150px;
background-image:url(${avatar});
background-position:center;
background-size:cover;
`

const LeftPart = styled.div `
display:flex;
justify-content:center;
align-items:center;
`

const Username = styled.div `
margin:0 40px;
`

const Line = styled.div `
background-color:grey;
height:60px;
width:1px;
`

const TransactionWrapper = styled.div `
margin:0 40px;
display:flex;
justify-content:center;
align-items:center;
flex-direction:column;
`

const Transaction = styled.div `
font-size:1.2rem;
font-weight:800;
`

const TransactionWord = styled.div `
font-size:0.8rem;
`

const FollowersWrappper = styled.div `
margin:0 40px;
display:flex;
justify-content:center;
align-items:center;
flex-direction:column;
`

const Followers = styled.div `
font-size:1.2rem;
font-weight:800;
`

const FollowersWord = styled.div `
font-size:0.8rem;
`

const EditProfile = styled.div `
text-align:center;
line-height:40px;
width:150px;
height:40px;
background-color:#1C1C1C;
border-radius:7px;
border:1;
color:white;
font-size:0.9rem;
`
const HR = styled.hr `
background-color:grey;
`

const LeftBodyPart = styled.div `
font-size:0.9rem;
width:30%;
display:flex;
justify-content:center;
align-items:flex-start;
flex-direction:column;
color:grey;
`

const RightBodyPart = styled.div `
width:70%;
`

const Messages = styled.div `
margin-bottom:20px;
&:hover {
	cusor:pointer;
	text-decoration:underline;
	color:#1C1C1C;
}
`

const MyItems = styled.div `
margin-bottom:20px;
&:hover {
	text-decoration:underline;
	color:#1C1C1C;
}
`

const MyProfile = styled.div `
margin-bottom:20px;
&:hover {
	text-decoration:underline;
	color:#1C1C1C;
}
`

const Settings = styled.div `
margin-bottom:20px;
&:hover {
	text-decoration:underline;
	color:#1C1C1C;
}
`

export default function Me () {
	return (
		<>
			<Header />
			<Navbar />
			<MePageWrapper>
				<MeHeader>
					<LeftPart>
						<Avatar />
						<Username>NoahHong</Username>
						<Line />
						<TransactionWrapper>
							<Transaction>3</Transaction>
							<TransactionWord>Transactions</TransactionWord>
						</TransactionWrapper>
						<Line />
						<FollowersWrappper>
							<Followers>3</Followers>
							<FollowersWord>Transactions</FollowersWord>
						</FollowersWrappper>
					</LeftPart>
					<EditProfile>Edit Profile</EditProfile>
				</MeHeader>
				<HR/>
				<MeBody>
					<LeftBodyPart>
						<Messages>Messages</Messages>
						<MyItems>MyItems</MyItems>
						<MyProfile>MyProfile</MyProfile>
						<Settings>Settings</Settings>
					</LeftBodyPart>
					<RightBodyPart>

					</RightBodyPart>
				</MeBody>
			</MePageWrapper>
		</>
	)
}
